MOD = 1_000_000_007

# Count numbers in [0, 10^L-1] with digit sum s (allow leading zeros)
def build_dp(maxL, maxS):
    dp = [[0]*(maxS+1) for _ in range(maxL+1)]
    dp[0][0] = 1
    for i in range(maxL):
        row = dp[i]
        nxt = dp[i+1]
        for s, v in enumerate(row):
            if v:
                m = min(9, maxS-s)
                for d in range(m+1):
                    nxt[s+d] += v
    return dp

# smallest x >= 1 such that count of positive integers <= x with digit sum n is >= m
# then x is the m-th occurrence

def count_leq(x, n, dp):
    if x <= 0:
        return 0
    digs = list(map(int, str(x)))
    L = len(digs)
    total = 0
    s = 0
    rem_len = L
    for i, dig in enumerate(digs):
        rem_len = L - i - 1
        for d in range(dig):
            need = n - (s + d)
            if 0 <= need < len(dp[rem_len]):
                total += dp[rem_len][need]
        s += dig
        if s > n:
            break
    else:
        if s == n:
            total += 1
    # exclude 0 if n==0, irrelevant here since n>=1
    return total


def kth_with_digit_sum(n, m, dp):
    # determine length L where cumulative count reaches m
    cum = 0
    L = 1
    while True:
        cntL = 0
        # first digit 1..9
        for d in range(1, 10):
            need = n - d
            if 0 <= need < len(dp[L-1]):
                cntL += dp[L-1][need]
        if cum + cntL >= m:
            break
        cum += cntL
        L += 1
    rank = m - cum
    # construct rank-th L-digit number with digit sum n
    res = []
    s = n
    for pos in range(L):
        start = 1 if pos == 0 else 0
        rem = L - pos - 1
        for d in range(start, 10):
            need = s - d
            cnt = dp[rem][need] if 0 <= need < len(dp[rem]) else 0
            if rank > cnt:
                rank -= cnt
            else:
                res.append(str(d))
                s -= d
                break
    return int(''.join(res))


def main():
    k = 10_000
    max_n = k**3
    # estimate max length needed. For n=max_n and m=n^4, asymptotically length about n/9 + O(log m)
    maxL = max_n // 9 + 50
    dp = build_dp(maxL, max_n)
    ans = 0
    for i in range(1, k+1):
        n = i*i*i
        m = n*n*n*n
        val = kth_with_digit_sum(n, m, dp)
        ans = (ans + val) % MOD
    print(ans)

if __name__ == '__main__':
    main()

