def count_completions(positions, deficit):
    dp = [0]*(deficit+1)
    dp[0] = 1
    for _ in range(positions):
        ndp = [0]*(deficit+1)
        for s, v in enumerate(dp):
            if not v: continue
            m = min(9, deficit-s)
            for e in range(m+1):
                ndp[s+e] += v
        dp = ndp
    return dp[deficit]


def count_len(q, r, t):
    D = 9*t + r
    L = q + t
    total = 0
    for e0 in range(0, min(8, D)+1):
        total += count_completions(L-1, D-e0)
    return total


def kth_with_digit_sum(n, m):
    q, rem = divmod(n, 9)
    if rem == 0:
        r = 0
    else:
        q += 1
        r = 9 - rem
    cum = 0
    t = 0
    while True:
        cnt = count_len(q, r, t)
        if cum + cnt >= m:
            break
        cum += cnt
        t += 1
    rank = m - cum
    D = 9*t + r
    L = q + t
    res = []
    rem_def = D
    for pos in range(L):
        if pos == 0:
            e_values = range(min(8, rem_def), -1, -1)
        else:
            e_values = range(min(9, rem_def), -1, -1)
        for e in e_values:
            cnt = count_completions(L-pos-1, rem_def-e)
